-- schema_and_seed.sql
-- Supabase: Dashboard → SQL Editor → вставити → Run

-- ВДЕ Карта України — схема БД
-- Запускати в Supabase: Dashboard → SQL Editor → Run

-- ── Таблиця станцій ──────────────────────────────────────────────────────────
create table if not exists stations (
  station_id           text primary key,
  name                 text,
  type                 text not null default 'solar',
  oblast               text,
  region               text,
  company              text,
  company_name         text,
  company_edrpou       text,
  phone                text,
  contact_phone        text,
  contact_email        text,
  website              text,
  capacity_mw          double precision,
  lat                  double precision,
  lon                  double precision,
  is_approximate       boolean default false,
  location_precision   text,
  location_confidence  text,
  license_num          text,
  license_date         text,
  address              text,
  site_location        text,
  official_object_name text,
  official_object_region text,
  official_technology  text,
  official_energy_source text,
  support_scheme       text,
  support_scheme_date  text,
  source               text,
  source_primary       text,
  verification_status  text,
  data_completeness_score integer,
  updated_at           timestamptz default now()
);

-- ── Таблиця заявок на оновлення від власників ────────────────────────────────
create table if not exists update_requests (
  id               bigserial primary key,
  station_id       text references stations(station_id),
  submitter_name   text,
  submitter_phone  text,
  submitter_email  text,
  capacity_mw      double precision,
  lat              double precision,
  lon              double precision,
  address_update   text,
  comment          text,
  status           text default 'new' check (status in ('new','reviewed','applied','rejected')),
  created_at       timestamptz default now()
);

-- Індекс для швидкого пошуку нових заявок
create index if not exists update_requests_status_idx on update_requests(status, created_at desc);



-- RLS — Row Level Security
-- Запускати після schema.sql

-- ── stations: читають всі, оновлює тільки service key ────────────────────────
alter table stations enable row level security;

create policy "stations_public_read"
  on stations for select
  using (true);

-- ── update_requests: вставляють всі, читає тільки service key ────────────────
alter table update_requests enable row level security;

create policy "update_requests_public_insert"
  on update_requests for insert
  with check (true);

-- Для перегляду заявок адміном: використовуйте Supabase Dashboard
-- або підключайтесь через SUPABASE_SERVICE_KEY (не anon key)



